float berechne_durchschnitt(int daten[], int n) {
    int summe = 0;
    for (int i = 0; i < n; i++) {
        summe += daten[i];
    }
    return (float)summe / n;
}

int main() {
    int daten[4];
    for (int i = 0; i < 4; i++) {
        scanf("%d", &daten[i]);
    }
    printf("%.2f", berechne_durchschnitt(daten, 4));
    return 0;
}

