    int z = 0;
    for (int i = 0; i < n; i++) {
        if (a[i] % 2 == 0) {
            z++;
        }
    }
    return z;
}

int main() {
    int a[] = {10, -4, 3, 0, 8, 5, 2};
    int n = sizeof(a) / sizeof(a[0]);
    printf("%d", zaehle_gerade(a, n));
    return 0;
}

